mapper.select:
select
id
from vehicle_domain_index


        functional_domain = #{functionalDomain,jdbcType=NUMERIC}


        AND index_name = #{indexName,jdbcType=VARCHAR}

SELECT vbi.id,
CONCAT(vb.brand_en, '-', vbi.vehicle_model) AS vehicle_model_info,
CONCAT(vb.brand, '-', vbi.vehicle_model) AS vehicle_model_info,
AVG(vdt.presentation_value) AS avg_score, vbi.vehicle_system_version as vehicle_system_version, vbi.test_date as test_date FROM vehicle_base_info vbi LEFT JOIN vehicle_brand vb ON vbi.brand_id = vb.id LEFT JOIN vehicle_domain_tree vdt ON vdt.vehicle_base_id = vbi.id LEFT JOIN vehicle_domain_index vdi ON vdi.id = vdt.domain_index_id WHERE vdi.id = #{domainIndexId}
AND vbi.id IN
#{id}
GROUP BY vbi.id,
vb.brand_en,
vb.brand,
vbi.vehicle_model,vbi.vehicle_system_version,vbi.test_date;
